def analyse_symptoms(symptoms: list[str]) -> list[dict[str, Any]]:
    matched_keys: list[str] = []
    for symptom in symptoms:
        s = symptom.lower().strip()
        for keyword, keys in SYMPTOM_MAP.items():
            if keyword in s or s in keyword:
                for k in keys:
                    if k not in matched_keys:
                        matched_keys.append(k)
    results = []
    for key in matched_keys:
        if key not in SYMPTOM_DB:
            continue
        entry = SYMPTOM_DB[key]
        results.append({
            "condition": key.replace("_", " ").title(),
            "deficiencies": entry["deficiencies"],
            "excesses": entry["excesses"],
            "root_causes": entry["root_causes"],
            "healing_foods": entry["healing_foods"],
            "avoid": entry["avoid"],
            "protocol": entry["protocol"],
        })
    return results
